// Curio question bank — v2 curated set (120 questions).
// Each: category, difficulty (1 easy .. 3 hard), question, options[4],
// answer (index into options), fact (the "depth fact" revealed after),
// and kids: true when suitable for curious 8-12 year olds (Kids mode pool).
// Categories: History, Science, Geography, Arts, Tech, Nature
// Provenance: authored + adversarially fact-checked 2026-07 (agent-verified:
// Geography, Tech; editor-verified: History, Science, Arts, Nature).
window.CURIO_QUESTIONS = [
  // ---------- HISTORY ----------
  { cat: "History", region: "Africa", diff: 1, kids: true, q: "Which ancient wonder still stands today?", options: ["Hanging Gardens of Babylon", "Great Pyramid of Giza", "Colossus of Rhodes", "Lighthouse of Alexandria"], answer: 1, fact: "The Great Pyramid was the tallest human-made structure on Earth for ~3,800 years.", src: "https://en.wikipedia.org/wiki/Great_Pyramid_of_Giza" },
  { cat: "History", region: "Africa", diff: 2, q: "The Rosetta Stone was key to deciphering which writing?", options: ["Cuneiform", "Egyptian hieroglyphs", "Linear B", "Mayan glyphs"], answer: 1, fact: "It repeats one decree in three scripts, letting scholars crack hieroglyphs in the 1820s.", src: "https://en.wikipedia.org/wiki/Rosetta_Stone" },
  { cat: "History", region: "Europe", diff: 2, kids: true, q: "Which empire built an extensive road network with the phrase 'all roads lead to' its capital?", options: ["Persian", "Roman", "Mongol", "Ottoman"], answer: 1, fact: "Rome's roads totalled over 400,000 km — about 80,500 km of it stone-paved.", src: "https://en.wikipedia.org/wiki/Roman_roads" },
  { cat: "History", region: "Europe", diff: 3, q: "The Treaty of Westphalia (1648) is credited with founding the modern idea of what?", options: ["Free trade", "The sovereign nation-state", "Universal suffrage", "Central banking"], answer: 1, fact: "It ended the Thirty Years' War and set the principle that states control their own internal affairs.", src: "https://en.wikipedia.org/wiki/Peace_of_Westphalia" },
  { cat: "History", region: "Europe", diff: 1, kids: true, q: "Who was the first woman to win a Nobel Prize?", options: ["Rosalind Franklin", "Marie Curie", "Ada Lovelace", "Dorothy Hodgkin"], answer: 1, fact: "Marie Curie later became the only person to win Nobels in two different sciences: physics and chemistry.", src: "https://en.wikipedia.org/wiki/Marie_Curie" },
  { cat: "History", region: "Europe", diff: 2, kids: true, q: "The printing press was popularized in Europe by whom?", options: ["Leonardo da Vinci", "Johannes Gutenberg", "Galileo Galilei", "William Caxton"], answer: 1, fact: "Within 50 years of Gutenberg's 1450s press, Europe printed an estimated 20 million books.", src: "https://en.wikipedia.org/wiki/Printing_press" },
  { cat: "History", region: "Asia", diff: 3, q: "Which civilization invented the concept of zero as a number?", options: ["Ancient Greece", "Ancient India", "Ancient Rome", "Ancient Egypt"], answer: 1, fact: "The symbol and rules for zero were formalized by Indian mathematician Brahmagupta around 628 CE.", src: "https://en.wikipedia.org/wiki/Brahmagupta" },
  { cat: "History", region: "Global", diff: 2, kids: true, q: "The Silk Road primarily connected China with what region?", options: ["The Americas", "The Mediterranean and Europe", "Australia", "Sub-Saharan Africa"], answer: 1, fact: "It traded more than silk — paper, gunpowder and the plague all travelled it too.", src: "https://en.wikipedia.org/wiki/Silk_Road" },
  { cat: "History", region: "Americas", diff: 1, kids: true, q: "Which South American civilization built Machu Picchu high in the Andes?", options: ["Aztec", "Maya", "Inca", "Olmec"], answer: 2, fact: "The Inca fitted Machu Picchu's stones together without any mortar — so precisely that a knife blade can't slip between them.", src: "https://en.wikipedia.org/wiki/Machu_Picchu" },
  { cat: "History", region: "Asia", diff: 1, kids: true, q: "The Great Wall, stretching thousands of kilometres, was built to protect what country?", options: ["China", "Japan", "India", "Mongolia"], answer: 0, fact: "Contrary to the famous myth, astronauts confirm the Great Wall can't be seen from the Moon — no human-made structure can.", src: "https://en.wikipedia.org/wiki/Great_Wall_of_China" },
  { cat: "History", region: "Global", diff: 1, kids: true, q: "Who was the first person to walk on the Moon, in 1969?", options: ["Neil Armstrong", "Buzz Aldrin", "Yuri Gagarin", "Michael Collins"], answer: 0, fact: "The Moon has no wind or rain, so the astronauts' boot prints could stay crisp for millions of years.", src: "https://en.wikipedia.org/wiki/Apollo_11" },
  { cat: "History", region: "Europe", diff: 1, kids: true, q: "The Vikings originally set sail from which region of the world?", options: ["The Mediterranean", "Central Asia", "The British Isles", "Scandinavia"], answer: 3, fact: "Vikings reached North America around 1000 CE — almost 500 years before Columbus — leaving a settlement at L'Anse aux Meadows in Canada.", src: "https://en.wikipedia.org/wiki/L%27Anse_aux_Meadows" },
  { cat: "History", region: "Africa", diff: 2, kids: true, q: "Mansa Musa, often called the richest person in history, ruled which West African empire?", options: ["Ghana Empire", "Songhai Empire", "Mali Empire", "Benin Empire"], answer: 2, fact: "On his 1324 pilgrimage to Mecca, Mansa Musa handed out so much gold in Cairo that its value there reportedly stayed depressed for years.", src: "https://en.wikipedia.org/wiki/Mansa_Musa" },
  { cat: "History", region: "Asia", diff: 2, kids: true, q: "Which city was Japan's imperial capital for over 1,000 years before Tokyo?", options: ["Osaka", "Nara", "Yokohama", "Kyoto"], answer: 3, fact: "Tokyo literally means 'eastern capital' — the city was renamed from Edo when the emperor moved there from Kyoto in 1868.", src: "https://en.wikipedia.org/wiki/Tokyo" },
  { cat: "History", region: "Americas", diff: 2, q: "The ruins of Tenochtitlan, the Aztec capital, lie beneath which modern city?", options: ["Lima", "Mexico City", "Guatemala City", "Bogotá"], answer: 1, fact: "Aztec farmers grew food on chinampas — artificial island gardens so productive that some still operate in Mexico City's Xochimilco district.", src: "https://en.wikipedia.org/wiki/Chinampa" },
  { cat: "History", region: "MiddleEast", diff: 2, q: "Which ancient people of Mesopotamia developed cuneiform, one of the world's earliest writing systems?", options: ["The Babylonians", "The Sumerians", "The Assyrians", "The Phoenicians"], answer: 1, fact: "The earliest cuneiform tablets are mostly receipts and inventories — writing was invented for accounting long before poems or stories.", src: "https://en.wikipedia.org/wiki/Cuneiform" },
  { cat: "History", region: "Asia", diff: 2, q: "Which Ming dynasty admiral led China's giant 'treasure fleets' across the Indian Ocean in the early 1400s?", options: ["Kublai Khan", "Qin Shi Huang", "Confucius", "Zheng He"], answer: 3, fact: "One of Zheng He's voyages brought a giraffe to the Ming court, where it was celebrated as a qilin — a mythical creature of good omen.", src: "https://en.wikipedia.org/wiki/Zheng_He" },
  { cat: "History", region: "Asia", diff: 3, q: "Which empire was the largest contiguous land empire in world history?", options: ["Roman Empire", "British Empire", "Mongol Empire", "Russian Empire"], answer: 2, fact: "The Mongols ran the Yam, a horse-relay postal network whose riders, swapping mounts at stations, could move messages hundreds of kilometres a day.", src: "https://en.wikipedia.org/wiki/Yam_(route)" },
  { cat: "History", region: "Africa", diff: 3, q: "Which African kingdom, centered in modern Ethiopia, grew rich on Red Sea trade and minted its own gold coins?", options: ["Kush", "Aksum", "Great Zimbabwe", "Carthage"], answer: 1, fact: "One of Aksum's giant carved obelisks was taken to Rome on Mussolini's orders in 1937 — Italy finally returned it to Ethiopia in 2005.", src: "https://en.wikipedia.org/wiki/Obelisk_of_Axum" },
  { cat: "History", region: "Europe", diff: 3, q: "How many years did the Hundred Years' War between England and France actually last?", options: ["116 years", "100 years", "99 years", "130 years"], answer: 0, fact: "Despite its name it ran 116 years (1337–1453) — a series of wars between England and France broken up by long truces.", src: "https://en.wikipedia.org/wiki/Hundred_Years%27_War" },


  // ---------- REGIONAL HISTORY (decolonized, region-tagged) ----------
  // -- Africa --
  { cat: "History", region: "Africa", diff: 1, kids: true, q: "The great medieval stone city of Great Zimbabwe gave its name to which modern country?", options: ["Zambia", "Zimbabwe", "Botswana", "Mozambique"], answer: 1, fact: "Its high walls rise from millions of granite blocks stacked without mortar; 'zimbabwe' comes from a Shona phrase meaning 'houses of stone'.", src: "https://en.wikipedia.org/wiki/Great_Zimbabwe" },
  { cat: "History", region: "Africa", diff: 2, q: "The world's largest mud-brick (adobe) building is the Great Mosque of Djenné, found in which West African country?", options: ["Mali", "Morocco", "Sudan", "Nigeria"], answer: 0, fact: "Each year the whole town of Djenné turns out for a festival to replaster the mosque by hand, smoothing its earthen walls after the rains.", src: "https://en.wikipedia.org/wiki/Great_Mosque_of_Djenn%C3%A9" },
  { cat: "History", region: "Africa", diff: 2, kids: true, q: "Which land, home to the ancient Kingdom of Kush, actually contains more ancient pyramids than Egypt?", options: ["Libya", "Sudan", "Ethiopia", "Chad"], answer: 1, fact: "Sudan holds roughly 200 ancient pyramids — more than double Egypt's — steep, sharp-sided royal tombs for the kings and queens of Kush.", src: "https://en.wikipedia.org/wiki/Nubian_pyramids" },
  { cat: "History", region: "Africa", diff: 1, kids: true, q: "In the Mali and Songhai empires, the city of Timbuktu became famous across the world as a great center of what?", options: ["Diamond mining", "Learning and books", "Shipbuilding", "Silk weaving"], answer: 1, fact: "Timbuktu's Sankore and other schools drew thousands of students; families there still guard hundreds of thousands of old manuscripts.", src: "https://en.wikipedia.org/wiki/Timbuktu" },
  { cat: "History", region: "Africa", diff: 2, q: "The Ghana Empire grew rich by taxing trans-Saharan caravans carrying gold and which other precious commodity?", options: ["Salt", "Tea", "Sugar", "Amber"], answer: 0, fact: "Salt was scarce in West Africa and gold plentiful, so Saharan caravans swapped one for the other — and Ghana's kings taxed every load.", src: "https://en.wikipedia.org/wiki/Ghana_Empire" },
  { cat: "History", region: "Africa", diff: 1, kids: true, q: "The Swahili coast city-states such as Kilwa and Mombasa grew wealthy trading across which ocean?", options: ["Atlantic Ocean", "Indian Ocean", "Pacific Ocean", "Southern Ocean"], answer: 1, fact: "Seasonal monsoon winds carried Swahili traders to Arabia, India and China; their Bantu language, Kiswahili, absorbed many Arabic words.", src: "https://en.wikipedia.org/wiki/Swahili_coast" },
  { cat: "History", region: "Africa", diff: 2, q: "In 1896 Ethiopia defeated an invading European army at the Battle of Adwa, keeping its independence. Which country did it defeat?", options: ["Britain", "France", "Italy", "Portugal"], answer: 2, fact: "Led by Emperor Menelik II and Empress Taytu Betul, Ethiopia routed the Italian army — a rare defeat of a European power in the Scramble for Africa.", src: "https://en.wikipedia.org/wiki/Battle_of_Adwa", deeper: ["Adwa became a rallying symbol of anti-colonial pride for Africans and people of African descent around the world.", "Italy invaded again in 1935 and occupied Ethiopia, but was driven out by 1941; it never became a lasting colony."] },
  { cat: "History", region: "Africa", diff: 3, q: "The celebrated 'Benin Bronzes' — intricate cast plaques and heads — were made by the Kingdom of Benin, in what is now which country?", options: ["Republic of Benin", "Ghana", "Nigeria", "Cameroon"], answer: 2, fact: "Cast in brass by the lost-wax method, the plaques lined the royal palace, recording the Edo kingdom's history in metal.", src: "https://en.wikipedia.org/wiki/Benin_Bronzes", deeper: ["British forces looted thousands of the works in 1897; many still sit in Western museums, though Nigeria has begun winning some back.", "Their fine casting stunned Europeans and undercut false claims that such sophisticated art could not be African in origin."] },
  { cat: "History", region: "Africa", diff: 3, q: "One of the largest empires in African history, ruled from the city of Gao and expanded by Askia Muhammad, was the:", options: ["Songhai Empire", "Zulu Kingdom", "Kanem-Bornu Empire", "Almoravid dynasty"], answer: 0, fact: "Askia Muhammad split the empire into provinces with governors, judges and an army, controlling Niger River trade and the hub of Timbuktu.", src: "https://en.wikipedia.org/wiki/Songhai_Empire" },
  { cat: "History", region: "Africa", diff: 3, q: "The 11 medieval churches of Lalibela in Ethiopia are famous because they were:", options: ["Built from imported marble", "Carved downward out of solid rock", "Made entirely of gold", "Floated on a lake"], answer: 1, fact: "Carved top-down from single blocks of rock about 800 years ago as a 'New Jerusalem', they are still living churches of Ethiopian Orthodoxy.", src: "https://en.wikipedia.org/wiki/Rock-Hewn_Churches,_Lalibela", deeper: ["Trenches and tunnels link the churches, and features were named for holy sites, recreating Jerusalem in the Ethiopian highlands.", "They were cut with hand tools like hammers and chisels; tradition says the work took about 24 years."] },
  // -- Americas --
  { cat: "History", region: "Americas", diff: 1, kids: true, q: "The Inca kept numbers and records without an alphabet, using bundles of knotted cords called what?", options: ["Quipu", "Papyrus", "Abacus", "Wampum"], answer: 0, fact: "A quipu's knots recorded numbers in base-10 — a knot's position on the cord marked ones, tens or hundreds, read by specialists called quipucamayocs.", src: "https://en.wikipedia.org/wiki/Quipu" },
  { cat: "History", region: "Americas", diff: 1, kids: true, q: "Many Indigenous peoples of the Americas grew three crops together as the 'Three Sisters': maize (corn), squash, and which third plant?", options: ["Beans", "Potatoes", "Rice", "Wheat"], answer: 0, fact: "The trio help one another: bean vines climb the cornstalks, the beans enrich the soil with nitrogen, and broad squash leaves shade out weeds.", src: "https://en.wikipedia.org/wiki/Three_Sisters_(agriculture)" },
  { cat: "History", region: "Americas", diff: 1, kids: true, q: "The Mexica (Aztec) founded Tenochtitlan where legend says they saw an eagle perched on a cactus. That scene is on the flag of which country today?", options: ["Mexico", "Peru", "Guatemala", "Colombia"], answer: 0, fact: "The eagle stands on a nopal cactus growing from a rock in the water — in Mexica tradition, the sign marking where to build Tenochtitlan, today's Mexico City.", src: "https://en.wikipedia.org/wiki/Flag_of_Mexico" },
  { cat: "History", region: "Americas", diff: 2, kids: true, q: "English words like 'canoe,' 'hammock,' and 'hurricane' come from the Taino — the people who first met Europeans in which part of the Americas?", options: ["The Caribbean", "The Andes", "The Great Plains", "Patagonia"], answer: 0, fact: "'Hurricane' comes from Taino juracan, 'canoe' from kanoa, 'hammock' from hamaca and 'barbecue' from barbacoa — all carried into English through Spanish.", src: "https://en.wikipedia.org/wiki/Ta%C3%ADno" },
  { cat: "History", region: "Americas", diff: 2, q: "Which people created the most fully developed writing system of the ancient Americas — a script of hundreds of glyphs?", options: ["The Maya", "The Inca", "The Mexica (Aztec)", "The Haudenosaunee"], answer: 0, fact: "Maya writing was logosyllabic — mixing word-signs and syllable-signs — so a word could be spelled several ways; it was largely deciphered only in the late 1900s.", src: "https://en.wikipedia.org/wiki/Maya_script" },
  { cat: "History", region: "Americas", diff: 2, q: "Cahokia, the largest city in the Americas north of Mexico before European contact, was built by Mississippian people near which modern US city?", options: ["St. Louis", "Chicago", "Atlanta", "Denver"], answer: 0, fact: "Monks Mound, its central earthwork, is the largest north of Mexico; around 1100 CE Cahokia may have held more people than London did at the time.", src: "https://en.wikipedia.org/wiki/Cahokia", deeper: ["Its builders moved an estimated 55 million cubic feet of earth by hand, basket-load by basket-load, to raise about 120 mounds.", "Rows of tall timber posts nicknamed 'Woodhenge' tracked the sun, marking the solstices and equinoxes."] },
  { cat: "History", region: "Americas", diff: 2, q: "Cliff Palace at Mesa Verde — a stone village built into a canyon alcove — was made by which people of the US Southwest?", options: ["Ancestral Puebloans", "The Inca", "The Haudenosaunee", "The Olmec"], answer: 0, fact: "At Chaco Canyon the same culture raised great houses like Pueblo Bonito — up to five storeys with about 800 rooms, built to track the sun's and moon's cycles.", src: "https://en.wikipedia.org/wiki/Pueblo_Bonito" },
  { cat: "History", region: "Americas", diff: 3, q: "The Haudenosaunee (Iroquois) Confederacy united nations under its Great Law of Peace. How many nations did it originally bring together?", options: ["Five", "Two", "Nine", "Thirteen"], answer: 0, fact: "The five founders were the Mohawk, Oneida, Onondaga, Cayuga and Seneca; the Tuscarora acceded in 1722, making it the Six Nations.", src: "https://en.wikipedia.org/wiki/Great_Law_of_Peace", deeper: ["The confederacy's emblem is a great eastern white pine, the Tree of Peace, standing for the nations joined as one.", "Its Great Law was recorded not on paper but on wampum — belts of shell beads encoding the message in pictograms."] },
  { cat: "History", region: "Americas", diff: 3, q: "The Maya were expert skywatchers. Their Dresden Codex is celebrated above all for a table charting the cycles of which planet?", options: ["Venus", "Mars", "Jupiter", "Saturn"], answer: 0, fact: "The codex's Venus table tracked the planet's cycles well enough to predict its risings, and its lunar tables line up with the timing of eclipses.", src: "https://en.wikipedia.org/wiki/Dresden_Codex" },
  { cat: "History", region: "Americas", diff: 3, q: "The Inca linked their empire with over 40,000 km of roads. With no horses or wheels, how were urgent messages relayed along them?", options: ["Relay runners", "Carrier pigeons", "Signal drums", "Smoke signals"], answer: 0, fact: "Chasqui runners dashed between waystations spaced about a day's walk apart, handing off spoken messages and quipus so news sped across the empire on foot.", src: "https://en.wikipedia.org/wiki/Inca_road_system", deeper: ["The roads leapt Andean gorges on woven-grass suspension bridges, which crews had to replace roughly every two years.", "Called Qhapaq Nan, the network laced together Tawantinsuyu — the 'four quarters' — from Colombia to Chile."] },
  // -- Asia --
  { cat: "History", region: "Asia", diff: 1, kids: true, q: "The Terracotta Army — thousands of life-sized clay soldiers — was buried to guard the tomb of which ruler?", options: ["Qin Shi Huang", "Confucius", "Kublai Khan", "Sun Tzu"], answer: 0, fact: "Qin Shi Huang was China's first emperor, uniting its warring states in 221 BCE. No two of the roughly 8,000 terracotta soldiers share the same face.", src: "https://en.wikipedia.org/wiki/Terracotta_Army", deeper: ["The central tomb mound has never been dug up; ancient records tell of rivers of mercury inside, and soil tests there really do show unusually high mercury.", "The clay warriors were once brightly painted, but the lacquer can flake off within minutes of meeting dry air after 2,000 years underground."] },
  { cat: "History", region: "Asia", diff: 1, kids: true, q: "In old Japan, warriors who served lords and followed a strict code called bushido were known as what?", options: ["Cossacks", "Janissaries", "Samurai", "Shaolin monks"], answer: 2, fact: "Bushido, 'the way of the warrior,' stressed loyalty and honour. On duty a samurai wore a matched pair of swords — a long katana and a shorter blade — called daisho.", src: "https://en.wikipedia.org/wiki/Samurai" },
  { cat: "History", region: "Asia", diff: 1, kids: true, q: "Angkor Wat, the largest religious monument in the world, was built in the 1100s by which empire?", options: ["Gupta Empire", "Chola Empire", "Majapahit Empire", "Khmer Empire"], answer: 3, fact: "Angkor Wat began as a Hindu temple to the god Vishnu, then gradually became a Buddhist site. It has appeared on Cambodia's national flag since 1863.", src: "https://en.wikipedia.org/wiki/Angkor_Wat", deeper: ["At its peak, greater Angkor sprawled over at least 1,000 sq km — bigger than modern Paris — likely the largest city of the pre-industrial world.", "Angkor's temples used more stone than all of ancient Egypt's monuments combined, and its farmland may have fed close to a million people."] },
  { cat: "History", region: "Asia", diff: 2, kids: true, q: "Korea's own alphabet, Hangul, was created in the 1440s under which king?", options: ["Gwanggaeto", "Sejong the Great", "Taejo", "Kublai Khan"], answer: 1, fact: "Hangul was made so ordinary people could read easily; the shapes of its consonants copy how the tongue and lips move to make each sound.", src: "https://en.wikipedia.org/wiki/Hangul", deeper: ["Many elite scholars scorned Hangul, preferring Chinese characters; it only became Korea's main script in the late 1800s. Koreans mark Hangul Day each October.", "Because its letters map so neatly onto sounds, Hangul is often praised as one of the most logical and easy-to-learn writing systems ever created."] },
  { cat: "History", region: "Asia", diff: 2, q: "Emperor Ashoka, who spread Buddhist teachings across South Asia, ruled which ancient empire?", options: ["Gupta Empire", "Mauryan Empire", "Mughal Empire", "Chola Empire"], answer: 1, fact: "Ashoka had edicts carved on rocks and pillars across his empire. The four-lion Lion Capital of Ashoka is now the national emblem of India.", src: "https://en.wikipedia.org/wiki/Ashoka" },
  { cat: "History", region: "Asia", diff: 2, q: "Gunpowder was first developed over a thousand years ago by alchemists in which country?", options: ["Persia", "India", "Egypt", "China"], answer: 3, fact: "Chinese alchemists stumbled on gunpowder around the 800s CE while seeking an elixir of eternal life — one of the 'Four Great Inventions' of ancient China.", src: "https://en.wikipedia.org/wiki/Gunpowder" },
  { cat: "History", region: "Asia", diff: 2, q: "At its 14th-century peak, the mighty Majapahit Empire ruled much of maritime Southeast Asia from its heartland on which island?", options: ["Sri Lanka", "Borneo", "Java", "Luzon"], answer: 2, fact: "Majapahit's chief minister Gajah Mada swore the famous Palapa oath — vowing to take no rest until he had united the archipelago's islands under Majapahit.", src: "https://en.wikipedia.org/wiki/Majapahit" },
  { cat: "History", region: "Asia", diff: 3, q: "The Silk Road city of Samarkand became the dazzling capital of whose empire in the late 1300s?", options: ["Timur (Tamerlane)", "Genghis Khan", "Cyrus the Great", "Babur"], answer: 0, fact: "Timur filled Samarkand with tiled mosques and madrasas. His grandson Ulugh Beg built an observatory there and measured the year to within about a minute.", src: "https://en.wikipedia.org/wiki/Ulugh_Beg" },
  { cat: "History", region: "Asia", diff: 3, q: "Srivijaya, a great maritime power that rose in the 600s CE, was famed across Asia as a center for studying which religion?", options: ["Zoroastrianism", "Shinto", "Islam", "Buddhism"], answer: 3, fact: "The Chinese monk Yijing spent six months at Srivijaya's capital, Palembang on Sumatra, in 671 CE; the empire was a Buddhist learning hub for centuries.", src: "https://en.wikipedia.org/wiki/Srivijaya" },
  { cat: "History", region: "Asia", diff: 3, q: "Which grandson of Genghis Khan founded China's Yuan dynasty and ruled from a city that is now Beijing?", options: ["Batu Khan", "Ögedei Khan", "Kublai Khan", "Timur"], answer: 2, fact: "Kublai Khan proclaimed the Yuan dynasty in 1271 and built his capital, Dadu, where Beijing now stands — the first non-Han dynasty to rule all of China.", src: "https://en.wikipedia.org/wiki/Yuan_dynasty" },
  // -- Europe --
  { cat: "History", region: "Europe", diff: 1, kids: true, q: "In which land were the ancient Olympic Games first held, at a sanctuary called Olympia?", options: ["Egypt", "Greece", "Italy", "Persia"], answer: 1, fact: "The ancient Games ran for nearly 1,200 years, and a sacred truce paused wars so athletes and spectators could travel to Olympia in safety.", src: "https://en.wikipedia.org/wiki/Ancient_Olympic_Games" },
  { cat: "History", region: "Europe", diff: 2, q: "Which ancient Greek city is remembered as an early birthplace of democracy?", options: ["Sparta", "Athens", "Corinth", "Thebes"], answer: 1, fact: "Athens was a direct democracy, but only free adult men could vote — women, enslaved people and foreigners were excluded, perhaps 4 in 5 residents.", src: "https://en.wikipedia.org/wiki/Athenian_democracy" },
  { cat: "History", region: "Europe", diff: 2, q: "Which Roman town, famously preserved under volcanic ash, was buried by Mount Vesuvius in 79 CE?", options: ["Pompeii", "Ostia", "Ravenna", "Capua"], answer: 0, fact: "Ash sealed the town so completely that archaeologists found loaves of bread, painted shop signs and wall graffiti — a snapshot of ordinary Roman life.", src: "https://en.wikipedia.org/wiki/Pompeii" },
  { cat: "History", region: "Europe", diff: 1, kids: true, q: "In medieval Europe, most ordinary people earned their living as what?", options: ["Peasant farmers", "Merchant traders", "Soldiers", "Craftsmen in guilds"], answer: 0, fact: "Many peasants were serfs, bound to a lord's land: they farmed his fields for protection and a small plot of their own, and couldn't leave without permission.", src: "https://en.wikipedia.org/wiki/Serfdom" },
  { cat: "History", region: "Europe", diff: 3, q: "The Black Death that swept Europe in the 1340s was a devastating outbreak of which disease?", options: ["Cholera", "Plague", "Smallpox", "Typhus"], answer: 1, fact: "It killed perhaps a third to a half of Europe's people in just a few years — among the deadliest disasters in all of human history.", src: "https://en.wikipedia.org/wiki/Black_Death", deeper: ["With so few workers left, surviving peasants could demand higher pay — helping to weaken serfdom across much of Europe.", "The bacterium behind it, Yersinia pestis, still causes plague today, but is now curable with antibiotics."] },
  { cat: "History", region: "Europe", diff: 2, kids: true, q: "The Renaissance is generally said to have begun in which Italian city?", options: ["Rome", "Venice", "Florence", "Paris"], answer: 2, fact: "'Renaissance' is French for 'rebirth' — thinkers and artists revived the learning of ancient Greece and Rome after the Middle Ages.", src: "https://en.wikipedia.org/wiki/Renaissance", deeper: ["The Medici who funded Florence's art were bankers, not kings — their fortune paid for work by Leonardo, Botticelli and Michelangelo.", "Scholars called 'humanists' tracked down ancient Greek and Latin manuscripts, reviving learning nearly lost in Europe."] },
  { cat: "History", region: "Europe", diff: 3, q: "In 1517 Martin Luther sparked the Reformation by publishing his Ninety-five Theses in which town?", options: ["Rome", "Geneva", "Wittenberg", "Paris"], answer: 2, fact: "Though written in Latin, the Theses were soon translated into German and printed, spreading across the region within about two weeks.", src: "https://en.wikipedia.org/wiki/Ninety-five_Theses", deeper: ["Luther was protesting 'indulgences' — payments the Church claimed could reduce the punishment for a person's sins.", "The movement split Western Christianity, creating Protestant churches independent of the Pope in Rome."] },
  { cat: "History", region: "Europe", diff: 2, q: "The Industrial Revolution began around the 1760s in which country?", options: ["France", "Great Britain", "Germany", "United States"], answer: 1, fact: "Early cotton mills relied on the labour of women and children, some working twelve-hour days, until reform laws slowly limited it.", src: "https://en.wikipedia.org/wiki/Industrial_Revolution" },
  { cat: "History", region: "Europe", diff: 3, q: "Whose greatly improved steam engine, with a separate condenser, became a driving force of the Industrial Revolution?", options: ["Isambard Kingdom Brunel", "James Watt", "George Stephenson", "Richard Arkwright"], answer: 1, fact: "Watt's design used up to five times less fuel than earlier engines — the unit of power, the watt, is named in his honour.", src: "https://en.wikipedia.org/wiki/James_Watt" },
  { cat: "History", region: "Europe", diff: 1, kids: true, q: "An early steam locomotive that won the 1829 Rainhill Trials was named what?", options: ["Rocket", "Comet", "Puffing Billy", "Locomotion"], answer: 0, fact: "Rocket reached about 48 km/h (30 mph) — dizzying then, when most people had never travelled faster than a galloping horse.", src: "https://en.wikipedia.org/wiki/Stephenson%27s_Rocket" },
  // -- Middle East --
  { cat: "History", region: "MiddleEast", diff: 1, q: "Which Babylonian king is remembered for issuing one of the earliest written law codes, carved onto a tall stone pillar?", options: ["Sargon of Akkad", "Hammurabi", "Nebuchadnezzar II", "Ashurbanipal"], answer: 1, fact: "His code was carved on a basalt pillar over 2 metres tall — now in the Louvre — setting fixed penalties so justice no longer varied case by case.", src: "https://en.wikipedia.org/wiki/Code_of_Hammurabi" },
  { cat: "History", region: "MiddleEast", diff: 1, kids: true, q: "Which Persian king founded the Achaemenid Empire and let the peoples he ruled keep their own customs and religions?", options: ["Cyrus the Great", "Xerxes I", "Darius III", "Cambyses II"], answer: 0, fact: "The Cyrus Cylinder, a clay barrel written in cuneiform, records his reign; the original is in the British Museum and a replica sits at the United Nations.", src: "https://en.wikipedia.org/wiki/Cyrus_Cylinder" },
  { cat: "History", region: "MiddleEast", diff: 2, kids: true, q: "The word 'algebra' comes from a book written by which scholar of Baghdad's House of Wisdom?", options: ["Omar Khayyam", "Ibn Sina", "Al-Razi", "Al-Khwarizmi"], answer: 3, fact: "The title word 'al-jabr' means 'restoration' — the step of balancing an equation by adding equal amounts to both sides; we now call the whole subject algebra.", src: "https://en.wikipedia.org/wiki/Al-Khwarizmi", deeper: ["The word 'algorithm' also comes from his name, which medieval Europe wrote in Latin as 'Algoritmi'.", "He helped spread Hindu-Arabic numerals — the 0-9 digits the world still writes with today."] },
  { cat: "History", region: "MiddleEast", diff: 1, kids: true, q: "The Phoenicians, seafaring traders of the eastern Mediterranean, are credited with spreading an early version of what?", options: ["The wheel", "The alphabet", "Paper", "Gunpowder"], answer: 1, fact: "Their alphabet had 22 letters and no vowels; the Greeks borrowed it and added vowels, and nearly every Western alphabet descends from it.", src: "https://en.wikipedia.org/wiki/Phoenician_alphabet", deeper: ["Our word 'alphabet' comes from its first two letters, 'aleph' and 'bet'.", "Traders carried the script across the sea from home cities like Tyre and Byblos in what is now Lebanon."] },
  { cat: "History", region: "MiddleEast", diff: 2, q: "The House of Wisdom, a celebrated centre of learning and translation, stood in which city?", options: ["Damascus", "Cordoba", "Baghdad", "Samarkand"], answer: 2, fact: "During the Abbasid era its scholars translated Greek, Persian and Indian works into Arabic, safeguarding knowledge that later flowed on to Europe.", src: "https://en.wikipedia.org/wiki/House_of_Wisdom" },
  { cat: "History", region: "MiddleEast", diff: 2, q: "In 1453 the Ottoman sultan Mehmed II captured which great city and made it his new capital?", options: ["Vienna", "Cairo", "Baghdad", "Constantinople"], answer: 3, fact: "Mehmed II was only about 21; his conquest ended the thousand-year Byzantine (Eastern Roman) Empire, and the city — later Istanbul — became the Ottoman capital.", src: "https://en.wikipedia.org/wiki/Fall_of_Constantinople" },
  { cat: "History", region: "MiddleEast", diff: 3, q: "The Epic of Gilgamesh, among the world's oldest surviving stories, was composed by which civilization?", options: ["Ancient Mesopotamia", "Ancient Egypt", "Ancient Greece", "The Indus Valley"], answer: 0, fact: "Preserved on clay tablets, it includes a great-flood tale in which a man builds a boat to survive — a story written centuries before the similar account in Genesis.", src: "https://en.wikipedia.org/wiki/Epic_of_Gilgamesh" },
  { cat: "History", region: "MiddleEast", diff: 3, q: "Persepolis, with its great columned halls, was the ceremonial capital of which empire?", options: ["The Ottoman Empire", "The Babylonian Empire", "The Achaemenid Persian Empire", "The Assyrian Empire"], answer: 2, fact: "Its Apadana staircase is carved with delegations from across the empire bringing gifts; Alexander of Macedon's army burned the palace in 330 BCE.", src: "https://en.wikipedia.org/wiki/Persepolis" },
  { cat: "History", region: "MiddleEast", diff: 3, q: "'The Canon of Medicine', a medical encyclopaedia used for centuries, was written by which scholar?", options: ["Ibn Battuta", "Al-Ghazali", "Rumi", "Ibn Sina (Avicenna)"], answer: 3, fact: "Completed around 1025, the Canon was still used as a standard medical textbook in European universities into the 1600s — roughly 600 years later.", src: "https://en.wikipedia.org/wiki/The_Canon_of_Medicine" },
  { cat: "History", region: "MiddleEast", diff: 2, kids: true, q: "Our 60-minute hour and 360-degree circle are inherited from the counting system of which ancient people?", options: ["The Romans", "The Babylonians", "The Egyptians", "The Greeks"], answer: 1, fact: "They counted in base 60 — a system begun by the Sumerians — and it still shapes how we measure time and the angles of a circle today.", src: "https://en.wikipedia.org/wiki/Sexagesimal", deeper: ["60 is the smallest number evenly divisible by 1, 2, 3, 4, 5 and 6, which made fractions easy to handle.", "They wrote every number by combining just two cuneiform marks — one for units and one for tens — pressed into clay."] },

  // ---------- SCIENCE ----------
  { cat: "Science", diff: 1, kids: true, q: "What gas do plants primarily absorb for photosynthesis?", options: ["Oxygen", "Nitrogen", "Carbon dioxide", "Hydrogen"], answer: 2, fact: "A large tree can absorb ~22 kg of CO2 per year and release enough oxygen for two people.", src: "https://en.wikipedia.org/wiki/Photosynthesis" },
  { cat: "Science", diff: 2, q: "What is the most abundant element in the universe?", options: ["Oxygen", "Carbon", "Hydrogen", "Helium"], answer: 2, fact: "Hydrogen makes up about 75% of all normal matter by mass.", src: "https://en.wikipedia.org/wiki/Hydrogen" },
  { cat: "Science", diff: 2, kids: true, q: "How many bones are in the adult human body?", options: ["206", "312", "180", "256"], answer: 0, fact: "Babies are born with ~300 bones; many fuse together as they grow.", src: "https://en.wikipedia.org/wiki/List_of_bones_of_the_human_skeleton" },
  { cat: "Science", diff: 3, q: "What does the 'c' represent in E = mc²?", options: ["A constant of gravity", "The speed of light", "Charge", "Specific heat"], answer: 1, fact: "Because c is squared and huge, a tiny bit of mass converts into an enormous amount of energy.", src: "https://en.wikipedia.org/wiki/Mass%E2%80%93energy_equivalence" },
  { cat: "Science", diff: 1, kids: true, q: "What is H2O more commonly known as?", options: ["Salt", "Water", "Hydrogen peroxide", "Ammonia"], answer: 1, fact: "Water is one of the few substances less dense as a solid than a liquid — which is why ice floats.", src: "https://en.wikipedia.org/wiki/Ice" },
  { cat: "Science", diff: 3, q: "Which particle carries a negative electric charge?", options: ["Proton", "Neutron", "Electron", "Photon"], answer: 2, fact: "Electrons are ~1,836 times lighter than protons yet define nearly all of chemistry.", src: "https://en.wikipedia.org/wiki/Electron" },
  { cat: "Science", diff: 2, q: "What part of the cell contains genetic material?", options: ["Mitochondria", "Nucleus", "Ribosome", "Membrane"], answer: 1, fact: "If you unravelled the DNA in a single cell it would stretch about 2 metres.", src: "https://en.wikipedia.org/wiki/DNA" },
  { cat: "Science", diff: 3, q: "At what temperature are Celsius and Fahrenheit equal?", options: ["0°", "-40°", "100°", "-273°"], answer: 1, fact: "-40 is the one point where both scales read the same number.", src: "https://en.wikipedia.org/wiki/Fahrenheit" },
  { cat: "Science", diff: 1, kids: true, q: "Which planet is known as the Red Planet?", options: ["Venus", "Jupiter", "Mars", "Mercury"], answer: 2, fact: "Mars is home to Olympus Mons, a volcano about 2.5 times the height of Mount Everest.", src: "https://en.wikipedia.org/wiki/Olympus_Mons" },
  { cat: "Science", diff: 1, kids: true, q: "What is the closest star to Earth?", options: ["Polaris", "Alpha Centauri", "Sirius", "The Sun"], answer: 3, fact: "Sunlight takes about 8 minutes to reach Earth — you always see the Sun as it was 8 minutes ago.", src: "https://en.wikipedia.org/wiki/Sunlight" },
  { cat: "Science", diff: 1, kids: true, q: "What force pulls a dropped ball down toward the ground?", options: ["Gravity", "Magnetism", "Friction", "Electricity"], answer: 0, fact: "Gravity is the weakest of nature's four fundamental forces — a small fridge magnet can beat the pull of the entire Earth.", src: "https://en.wikipedia.org/wiki/Fundamental_interaction" },
  { cat: "Science", diff: 1, kids: true, q: "What is the hardest naturally occurring material?", options: ["Quartz", "Iron", "Diamond", "Granite"], answer: 2, fact: "Diamond and pencil graphite are both pure carbon — only the arrangement of the atoms makes one hard and the other soft.", src: "https://en.wikipedia.org/wiki/Allotropes_of_carbon" },
  { cat: "Science", diff: 2, kids: true, q: "How many chambers does the human heart have?", options: ["Two", "Three", "Four", "Five"], answer: 2, fact: "Your heart beats about 100,000 times every day — over 2.5 billion beats in an average lifetime.", src: "https://en.wikipedia.org/wiki/Heart" },
  { cat: "Science", diff: 2, q: "What is the chemical symbol for gold?", options: ["Go", "Au", "Gd", "Ag"], answer: 1, fact: "Gold is so malleable that a single gram can be hammered into a sheet about one square metre in size.", src: "https://en.wikipedia.org/wiki/Gold" },
  { cat: "Science", diff: 2, q: "Which gas makes up about 78% of Earth's atmosphere?", options: ["Oxygen", "Nitrogen", "Carbon dioxide", "Argon"], answer: 1, fact: "You can't use the nitrogen you inhale — it must first be 'fixed' by bacteria or lightning into compounds plants can absorb.", src: "https://en.wikipedia.org/wiki/Nitrogen_fixation" },
  { cat: "Science", diff: 2, q: "What process produces the Sun's energy?", options: ["Nuclear fission", "Nuclear fusion", "Chemical combustion", "Gravitational collapse"], answer: 1, fact: "The Sun converts about 4 million tonnes of matter into pure energy every single second — with fuel for billions of years more.", src: "https://en.wikipedia.org/wiki/Sun" },
  { cat: "Science", diff: 2, kids: true, q: "Where in the human body would you find the femur?", options: ["In the arm", "In the leg", "In the skull", "In the spine"], answer: 1, fact: "The femur, your thigh bone, is the longest and strongest bone in your body — about a quarter of your total height.", src: "https://en.wikipedia.org/wiki/Femur" },
  { cat: "Science", diff: 3, q: "What is the most abundant metal in Earth's crust?", options: ["Iron", "Copper", "Aluminium", "Zinc"], answer: 2, fact: "In 1884 aluminium was still so costly that the Washington Monument was capped with a small pyramid of it as a showpiece.", src: "https://en.wikipedia.org/wiki/Washington_Monument" },
  { cat: "Science", diff: 3, q: "Approximately what temperature is absolute zero in Celsius?", options: ["-100°C", "-273°C", "-460°C", "0°C"], answer: 1, fact: "Absolute zero can never quite be reached — but labs have chilled atoms to less than a billionth of a degree above it.", src: "https://en.wikipedia.org/wiki/Absolute_zero" },
  { cat: "Science", diff: 3, q: "Who created the periodic table, leaving gaps for elements not yet discovered?", options: ["Antoine Lavoisier", "John Dalton", "Dmitri Mendeleev", "Niels Bohr"], answer: 2, fact: "Mendeleev predicted the properties of the missing elements — when gallium and germanium were found, they matched almost exactly.", src: "https://en.wikipedia.org/wiki/Dmitri_Mendeleev" },

  // ---------- GEOGRAPHY ----------
  { cat: "Geography", diff: 1, kids: true, q: "What is the largest ocean on Earth?", options: ["Atlantic", "Indian", "Arctic", "Pacific"], answer: 3, fact: "The Pacific is bigger than all Earth's land area combined.", src: "https://en.wikipedia.org/wiki/Pacific_Ocean" },
  { cat: "Geography", diff: 2, q: "Which country has the most time zones?", options: ["Russia", "USA", "China", "France"], answer: 3, fact: "France, counting overseas territories, spans 12 time zones — more than any other country.", src: "https://en.wikipedia.org/wiki/Time_in_France" },
  { cat: "Geography", diff: 1, kids: true, q: "Mount Everest sits on the border of Nepal and which country?", options: ["India", "China", "Bhutan", "Pakistan"], answer: 1, fact: "Everest grows about 4 mm taller each year as tectonic plates keep colliding.", src: "https://en.wikipedia.org/wiki/Mount_Everest" },
  { cat: "Geography", diff: 2, kids: true, q: "The Sahara Desert is located primarily on which continent?", options: ["Asia", "Australia", "Africa", "South America"], answer: 2, fact: "The Sahara is roughly the size of the entire United States.", src: "https://en.wikipedia.org/wiki/Sahara" },
  { cat: "Geography", diff: 3, q: "What is the capital of Australia?", options: ["Sydney", "Melbourne", "Canberra", "Perth"], answer: 2, fact: "Canberra was purpose-built as a compromise between rivals Sydney and Melbourne.", src: "https://en.wikipedia.org/wiki/Canberra" },
  { cat: "Geography", diff: 2, kids: true, q: "The Amazon River flows mainly through which country?", options: ["Colombia", "Peru", "Brazil", "Venezuela"], answer: 2, fact: "The Amazon discharges more water than the next seven largest rivers combined.", src: "https://en.wikipedia.org/wiki/Amazon_River" },
  { cat: "Geography", diff: 3, kids: true, q: "Which is the only country that is also a continent?", options: ["Greenland", "Australia", "Antarctica", "Iceland"], answer: 1, fact: "Australia is the smallest continent — because it counts as a continent, Greenland gets the title of world's largest island.", src: "https://en.wikipedia.org/wiki/List_of_islands_by_area" },
  { cat: "Geography", diff: 1, kids: true, q: "Which river runs through Egypt's capital, Cairo?", options: ["Tigris", "Nile", "Euphrates", "Congo"], answer: 1, fact: "The Nile is about 6,650 km long and fed one of humanity's earliest great civilizations.", src: "https://en.wikipedia.org/wiki/Nile" },
  { cat: "Geography", diff: 1, kids: true, q: "Which country is the largest in the world by area?", options: ["Canada", "Russia", "China", "United States"], answer: 1, fact: "Russia spans 11 time zones — the Trans-Siberian train from Moscow to Vladivostok takes about a week.", src: "https://en.wikipedia.org/wiki/Time_in_Russia" },
  { cat: "Geography", diff: 1, kids: true, q: "What is the capital of Japan?", options: ["Kyoto", "Osaka", "Tokyo", "Hiroshima"], answer: 2, fact: "Tokyo means 'eastern capital' — the emperor moved there in 1868 from Kyoto, Japan's capital for over 1,000 years.", src: "https://en.wikipedia.org/wiki/Tokyo" },
  { cat: "Geography", diff: 1, kids: true, q: "Which continent is the coldest on Earth?", options: ["Asia", "North America", "Europe", "Antarctica"], answer: 3, fact: "Antarctica is technically Earth's largest desert — some of its Dry Valleys haven't seen rain in nearly 2 million years.", src: "https://en.wikipedia.org/wiki/Antarctica" },
  { cat: "Geography", diff: 1, kids: true, q: "Which imaginary line circles Earth exactly halfway between the poles?", options: ["The Equator", "The Prime Meridian", "The Tropic of Cancer", "The International Date Line"], answer: 0, fact: "You weigh about 0.5% less at the Equator than at the poles — Earth's spin and bulge weaken gravity's pull there.", src: "https://en.wikipedia.org/wiki/Gravity_of_Earth" },
  { cat: "Geography", diff: 2, kids: true, q: "What is the longest mountain range on land?", options: ["The Himalayas", "The Andes", "The Rocky Mountains", "The Alps"], answer: 1, fact: "The Andes stretch about 7,000 km through seven countries and contain the world's highest volcanoes.", src: "https://en.wikipedia.org/wiki/Andes" },
  { cat: "Geography", diff: 2, kids: true, q: "Nairobi is the capital of which African country?", options: ["Tanzania", "Ethiopia", "Kenya", "Uganda"], answer: 2, fact: "Nairobi has a national park where wild lions and giraffes roam within sight of downtown skyscrapers.", src: "https://en.wikipedia.org/wiki/Nairobi_National_Park" },
  { cat: "Geography", diff: 2, q: "Which two countries share the longest land border in the world?", options: ["Russia and China", "United States and Canada", "Argentina and Chile", "United States and Mexico"], answer: 1, fact: "The border includes 'the Slash' — a 6-metre-wide treeless strip clear-cut through thousands of kilometres of forest.", src: "https://en.wikipedia.org/wiki/Canada%E2%80%93United_States_border" },
  { cat: "Geography", diff: 2, q: "The Strait of Gibraltar separates Spain from which country?", options: ["Algeria", "Tunisia", "Portugal", "Morocco"], answer: 3, fact: "At its narrowest the strait is only about 13 km wide — on a clear day, you can see Africa from Europe.", src: "https://en.wikipedia.org/wiki/Strait_of_Gibraltar" },
  { cat: "Geography", diff: 2, q: "Where is Lake Baikal, the deepest lake on Earth?", options: ["Russia", "Canada", "Mongolia", "China"], answer: 0, fact: "Baikal holds about one-fifth of Earth's unfrozen fresh surface water — more than all five North American Great Lakes combined.", src: "https://en.wikipedia.org/wiki/Lake_Baikal" },
  { cat: "Geography", diff: 3, q: "How many capital cities does South Africa have?", options: ["One", "Two", "Three", "Four"], answer: 2, fact: "Pretoria is the executive capital, Cape Town the legislative, and Bloemfontein the judicial — a compromise from 1910.", src: "https://en.wikipedia.org/wiki/Pretoria" },
  { cat: "Geography", diff: 3, q: "What is the driest non-polar desert on Earth?", options: ["Gobi", "Kalahari", "Atacama", "Mojave"], answer: 2, fact: "Parts of the Atacama have never recorded rainfall — NASA uses its Mars-like soil to test rover instruments.", src: "https://en.wikipedia.org/wiki/Atacama_Desert" },
  { cat: "Geography", diff: 3, q: "Which country is 'doubly landlocked' — surrounded only by other landlocked countries?", options: ["Mongolia", "Uzbekistan", "Bolivia", "Nepal"], answer: 1, fact: "Only two doubly landlocked countries exist: Uzbekistan and tiny Liechtenstein, tucked in the Alps.", src: "https://en.wikipedia.org/wiki/Landlocked_country" },

  // ---------- ARTS & LETTERS ----------
  { cat: "Arts", diff: 1, kids: true, q: "Who painted the Mona Lisa?", options: ["Michelangelo", "Leonardo da Vinci", "Raphael", "Donatello"], answer: 1, fact: "The Mona Lisa has no visible eyebrows — a fashion of the era, or lost to cleaning." },
  { cat: "Arts", diff: 2, q: "Which playwright wrote 'Hamlet'?", options: ["Christopher Marlowe", "William Shakespeare", "Ben Jonson", "Oscar Wilde"], answer: 1, fact: "Shakespeare coined or popularized over 1,700 words still used in English today." },
  { cat: "Arts", diff: 2, kids: true, q: "The Starry Night was painted by which artist?", options: ["Claude Monet", "Vincent van Gogh", "Paul Cézanne", "Edvard Munch"], answer: 1, fact: "Van Gogh painted it from memory in an asylum, and sold only one painting in his lifetime." },
  { cat: "Arts", diff: 3, kids: true, q: "Which composer continued writing music after going deaf?", options: ["Mozart", "Beethoven", "Bach", "Chopin"], answer: 1, fact: "Beethoven composed his monumental Ninth Symphony when almost completely deaf." },
  { cat: "Arts", diff: 3, q: "'One Hundred Years of Solitude' was written by which author?", options: ["Pablo Neruda", "Gabriel García Márquez", "Jorge Luis Borges", "Isabel Allende"], answer: 1, fact: "It's the flagship of 'magical realism' and has sold over 50 million copies." },
  { cat: "Arts", diff: 1, kids: true, q: "How many strings does a standard violin have?", options: ["Four", "Six", "Five", "Seven"], answer: 0, fact: "Those four strings can produce an astonishing range through position and bowing." },
  { cat: "Arts", diff: 2, q: "The Sistine Chapel ceiling was painted by whom?", options: ["Raphael", "Michelangelo", "Botticelli", "Titian"], answer: 1, fact: "Michelangelo spent about four years painting it, mostly standing and craning upward — not lying down." },
  { cat: "Arts", diff: 3, kids: true, q: "Which ballet features 'The Dance of the Sugar Plum Fairy'?", options: ["Swan Lake", "The Nutcracker", "Giselle", "The Firebird"], answer: 1, fact: "Tchaikovsky used the then-new celesta for its shimmering, music-box tone." },
  { cat: "Arts", diff: 1, kids: true, q: "What is a painting of a person's face and shoulders called?", options: ["Portrait", "Landscape", "Still life", "Mural"], answer: 0, fact: "A portrait an artist makes of themselves is a self-portrait — Rembrandt made around 80 of them, a visual diary of his whole adult life." },
  { cat: "Arts", diff: 1, kids: true, q: "How many keys does a standard modern piano have?", options: ["66", "76", "88", "96"], answer: 2, fact: "The piano's full name is 'pianoforte' — Italian for 'soft-loud' — because unlike the harpsichord it could play both gently and thunderously." },
  { cat: "Arts", diff: 1, kids: true, q: "Which ancient Greek epic poem follows the hero Odysseus's long sea journey home?", options: ["The Iliad", "The Odyssey", "The Aeneid", "Beowulf"], answer: 1, fact: "The hero's name gave English the word 'odyssey' — and the poem famously begins in the middle of the story, a trick called 'in medias res'." },
  { cat: "Arts", diff: 1, kids: true, q: "The Beatles formed in which English city?", options: ["London", "Manchester", "Birmingham", "Liverpool"], answer: 3, fact: "In one week of April 1964, The Beatles became the first act ever to hold all five top spots on the US Billboard singles chart." },
  { cat: "Arts", diff: 2, kids: true, q: "Who created the famous Japanese woodblock print 'The Great Wave off Kanagawa'?", options: ["Utagawa Hiroshige", "Katsushika Hokusai", "Kitagawa Utamaro", "Yayoi Kusama"], answer: 1, fact: "Hokusai made it in his early seventies for the series 'Thirty-six Views of Mount Fuji' — Fuji is the tiny peak behind the towering wave." },
  { cat: "Arts", diff: 2, kids: true, q: "Mexican painter Frida Kahlo is most famous for which kind of artwork?", options: ["Stained glass windows", "Marble sculptures", "Self-portraits", "Watercolour seascapes"], answer: 2, fact: "After a bus accident at 18, Kahlo began painting in bed with a mirror fixed overhead — about a third of her works show her own face." },
  { cat: "Arts", diff: 2, q: "Who is the storyteller who narrates the tales of 'One Thousand and One Nights'?", options: ["Aladdin", "Sinbad the Sailor", "Scheherazade", "Morgiana"], answer: 2, fact: "Aladdin and Ali Baba are missing from the earliest Arabic manuscripts — French translator Antoine Galland added those tales in the early 1700s." },
  { cat: "Arts", diff: 2, q: "An architect from which country designed the Sydney Opera House?", options: ["Denmark", "Australia", "United States", "Brazil"], answer: 0, fact: "Danish architect Jørn Utzon resigned mid-build in 1966 and never returned to see his masterpiece finished — it finally opened in 1973." },
  { cat: "Arts", diff: 2, q: "Which artist painted 'The Scream'?", options: ["Gustav Klimt", "Salvador Dalí", "Wassily Kandinsky", "Edvard Munch"], answer: 3, fact: "Munch made four versions of The Scream; two were stolen from Oslo museums in 1994 and 2004, and both were eventually recovered." },
  { cat: "Arts", diff: 3, q: "'The Tale of Genji', often called the world's first novel, was written in which country?", options: ["China", "Persia", "Japan", "Korea"], answer: 2, fact: "Murasaki Shikibu, a lady-in-waiting at Japan's imperial court, wrote it around 1000 CE — centuries before the printing press reached Europe." },
  { cat: "Arts", diff: 3, q: "Which Nigerian writer's 1958 novel 'Things Fall Apart' became a classic of world literature?", options: ["Wole Soyinka", "Chinua Achebe", "Ben Okri", "Buchi Emecheta"], answer: 1, fact: "Achebe took the title from a W.B. Yeats poem, 'The Second Coming'; the novel has been translated into more than 50 languages." },
  { cat: "Arts", diff: 3, q: "Which architect designed New York's spiral-shaped Guggenheim Museum?", options: ["Frank Gehry", "Le Corbusier", "Zaha Hadid", "Frank Lloyd Wright"], answer: 3, fact: "Wright wanted visitors to ride the lift up and stroll down the spiral ramp; the museum opened in 1959, six months after his death." },

  // ---------- TECH & MATH ----------
  { cat: "Tech", diff: 1, q: "What does 'HTTP' stand for?", options: ["HyperText Transfer Protocol", "High Transfer Text Program", "Hyperlink Text Transit Path", "Home Tool Transfer Protocol"], answer: 0, fact: "HTTP was invented by Tim Berners-Lee around 1989–91, along with the first web browser." },
  { cat: "Tech", diff: 2, q: "In binary, what number does '1010' represent?", options: ["8", "10", "12", "5"], answer: 1, fact: "Each place doubles: 8 + 0 + 2 + 0 = 10." },
  { cat: "Tech", diff: 3, kids: true, q: "Who is often called the first computer programmer?", options: ["Grace Hopper", "Ada Lovelace", "Alan Turing", "Charles Babbage"], answer: 1, fact: "In the 1840s Ada Lovelace wrote an algorithm for Babbage's never-built Analytical Engine." },
  { cat: "Tech", diff: 2, kids: true, q: "What is the value of pi (π) to two decimals?", options: ["3.14", "3.41", "2.72", "1.62"], answer: 0, fact: "Pi has been computed to over 100 trillion digits, yet 15 digits suffice for most engineering." },
  { cat: "Tech", diff: 3, kids: true, q: "A prime number is divisible only by 1 and what?", options: ["Zero", "Itself", "Two", "Ten"], answer: 1, fact: "2 is the only even prime — every other even number is divisible by 2." },
  { cat: "Tech", diff: 1, kids: true, q: "What does 'CPU' stand for?", options: ["Central Processing Unit", "Computer Power Unit", "Central Program Utility", "Core Processing Unit"], answer: 0, fact: "Modern CPUs can perform billions of operations per second across multiple cores." },
  { cat: "Tech", diff: 3, kids: true, q: "What is the next number in the Fibonacci sequence: 1, 1, 2, 3, 5, 8, ...?", options: ["11", "12", "13", "15"], answer: 2, fact: "Each Fibonacci number is the sum of the two before it — 5 + 8 = 13." },
  { cat: "Tech", diff: 2, q: "Which company released the first mass-market GUI personal computer, the Macintosh?", options: ["IBM", "Apple", "Microsoft", "Xerox"], answer: 1, fact: "Apple's 1984 Mac popularized ideas Xerox PARC had pioneered but never sold widely." },
  { cat: "Tech", diff: 1, kids: true, q: "How many bits make up one byte?", options: ["4", "16", "8", "32"], answer: 2, fact: "The word 'byte' was coined at IBM in 1956 and deliberately spelled with a 'y' so a typo could never turn it into 'bit'." },
  { cat: "Tech", diff: 1, kids: true, q: "Which of these units of digital storage is the largest?", options: ["Megabyte", "Terabyte", "Kilobyte", "Gigabyte"], answer: 1, fact: "One terabyte holds about a million megabytes — and big data centers now talk in exabytes, each a million terabytes." },
  { cat: "Tech", diff: 1, kids: true, q: "What was the shell of the very first computer mouse made of?", options: ["Plastic", "Rubber", "Wood", "Glass"], answer: 2, fact: "Inventor Douglas Engelbart's team named it 'mouse' because the cord trailing out the back looked like a tail." },
  { cat: "Tech", diff: 1, kids: true, q: "Which of these programs is a web browser?", options: ["Excel", "Chrome", "Photoshop", "Spotify"], answer: 1, fact: "The first hit browser, Mosaic (1993), popularized showing pictures inside the page instead of in separate windows." },
  { cat: "Tech", diff: 2, q: "In which decade was the first email sent over the ARPANET?", options: ["1950s", "1960s", "1970s", "1990s"], answer: 2, fact: "Ray Tomlinson picked the @ symbol to separate user from machine, and recalled his first test message as something like 'QWERTYUIOP'." },
  { cat: "Tech", diff: 2, q: "What was the name of the room-sized electronic computer unveiled at the University of Pennsylvania in 1946?", options: ["UNIVAC", "Colossus", "EDSAC", "ENIAC"], answer: 3, fact: "ENIAC weighed about 27 tonnes — and its six original programmers were all women, hired as mathematicians." },
  { cat: "Tech", diff: 2, kids: true, q: "In Morse code, what pattern makes up the distress signal 'SOS'?", options: ["Three dots, three dashes, three dots", "Three dashes, three dots, three dashes", "Six dots and six dashes", "Nine dashes in a row"], answer: 0, fact: "SOS doesn't stand for anything — it was adopted in 1906 simply because the pattern is quick to send and hard to mistake." },
  { cat: "Tech", diff: 2, kids: true, q: "The QWERTY keyboard layout was originally designed for which machine?", options: ["Typewriter", "Telegraph", "Cash register", "Printing press"], answer: 0, fact: "'Typewriter' is one of the longest common English words you can type using only QWERTY's top row of letters." },
  { cat: "Tech", diff: 2, q: "Computer chips are built from silicon — refined from what common material?", options: ["Sand", "Coal", "Clay", "Seawater"], answer: 0, fact: "Chip-grade silicon must be 99.9999999% pure — 'nine nines', among the purest materials humans have ever made." },
  { cat: "Tech", diff: 3, q: "In the hexadecimal number system, what value does the digit 'F' represent?", options: ["16", "10", "12", "15"], answer: 3, fact: "Two hex digits describe exactly one byte — that's why web colors like #FF6600 are written with six of them." },
  { cat: "Tech", diff: 3, q: "The famous test of whether a machine can pass as human in conversation is named after whom?", options: ["John von Neumann", "Alan Turing", "Claude Shannon", "Marvin Minsky"], answer: 1, fact: "Turing's 1950 paper opened with 'Can machines think?' — then swapped that question for his 'imitation game'." },
  { cat: "Tech", diff: 3, q: "In 1969 the first ARPANET link connected UCLA to which other institution?", options: ["MIT", "Harvard", "Bell Labs", "Stanford Research Institute"], answer: 3, fact: "The first message was meant to be 'LOGIN', but the system crashed after two letters — so the internet era began with 'LO'." },

  // ---------- NATURE ----------
  { cat: "Nature", diff: 1, kids: true, q: "What is the largest animal ever known to have lived?", options: ["African elephant", "Blue whale", "Argentinosaurus", "Giant squid"], answer: 1, fact: "A blue whale's heart alone can weigh as much as a small car." },
  { cat: "Nature", diff: 2, kids: true, q: "Which is the only mammal capable of true sustained flight?", options: ["Flying squirrel", "Bat", "Sugar glider", "Colugo"], answer: 1, fact: "Bats make up about a fifth of all mammal species." },
  { cat: "Nature", diff: 2, kids: true, q: "How many hearts does an octopus have?", options: ["One", "Two", "Three", "Four"], answer: 2, fact: "Two hearts pump blood to the gills, one to the body — and their blood is blue." },
  { cat: "Nature", diff: 1, kids: true, q: "What do bees collect to make honey?", options: ["Pollen", "Nectar", "Sap", "Water"], answer: 1, fact: "A single bee makes about 1/12 of a teaspoon of honey in its entire life." },
  { cat: "Nature", diff: 3, kids: true, q: "Which tree species is the tallest living thing on Earth?", options: ["Giant sequoia", "Coast redwood", "Douglas fir", "Eucalyptus"], answer: 1, fact: "The tallest coast redwood, 'Hyperion', stands over 115 metres — taller than the Statue of Liberty." },
  { cat: "Nature", diff: 2, kids: true, q: "A group of lions is called a what?", options: ["Pack", "Herd", "Pride", "Colony"], answer: 2, fact: "Lions are the only truly social big cats, living in prides of related females." },
  { cat: "Nature", diff: 3, kids: true, q: "Which animal has the longest known migration?", options: ["Monarch butterfly", "Arctic tern", "Humpback whale", "Caribou"], answer: 1, fact: "The Arctic tern flies pole to pole, over 70,000 km a year — seeing two summers annually." },
  { cat: "Nature", diff: 1, kids: true, q: "What is the fastest land animal?", options: ["Lion", "Cheetah", "Pronghorn", "Greyhound"], answer: 1, fact: "A cheetah can go 0–100 km/h in about three seconds — faster acceleration than most sports cars." },
  { cat: "Nature", diff: 1, kids: true, q: "What is the largest land animal alive today?", options: ["African elephant", "Hippopotamus", "White rhinoceros", "Giraffe"], answer: 0, fact: "An elephant's trunk has no bones but around 40,000 muscles — the entire human body has only about 600." },
  { cat: "Nature", diff: 1, kids: true, q: "What do we call an animal that eats only plants?", options: ["Carnivore", "Omnivore", "Herbivore", "Insectivore"], answer: 2, fact: "Plant-eaters often have far longer intestines than meat-eaters, giving tough fibre more time to break down." },
  { cat: "Nature", diff: 1, kids: true, q: "Which is the largest species of big cat?", options: ["Lion", "Jaguar", "Tiger", "Leopard"], answer: 2, fact: "No two tigers share the same stripe pattern — and the stripes go right down to their skin, not just the fur." },
  { cat: "Nature", diff: 1, kids: true, q: "How many legs does an insect have?", options: ["Four", "Six", "Eight", "Ten"], answer: 1, fact: "Every insect has six legs and three body parts; spiders have eight legs and aren't insects at all." },
  { cat: "Nature", diff: 2, q: "On the Mohs scale of hardness, which of these minerals is the hardest?", options: ["Corundum", "Quartz", "Topaz", "Diamond"], answer: 3, fact: "Natural diamonds form about 150 km underground and ride to the surface in rare, deep volcanic eruptions." },
  { cat: "Nature", diff: 2, kids: true, q: "Which food, if sealed properly, essentially never spoils?", options: ["Bread", "Honey", "Cheese", "Rice"], answer: 1, fact: "Archaeologists have found honey in ancient Egyptian tombs still perfectly edible — its low moisture and acidity block microbes." },
  { cat: "Nature", diff: 2, kids: true, q: "What is a baby kangaroo called?", options: ["Cub", "Kit", "Joey", "Calf"], answer: 2, fact: "A newborn joey is about the size of a jellybean and crawls unaided into its mother's pouch to keep growing." },
  { cat: "Nature", diff: 2, kids: true, q: "What is the largest living bird?", options: ["Andean condor", "Emu", "Albatross", "Ostrich"], answer: 3, fact: "An ostrich's eye is about 5 cm across — larger than its own brain." },
  { cat: "Nature", diff: 2, q: "What is a violently rotating column of air that touches the ground called?", options: ["Hurricane", "Cyclone", "Tornado", "Typhoon"], answer: 2, fact: "The strongest tornadoes pack winds over 480 km/h — the fastest winds ever measured near Earth's surface." },
  { cat: "Nature", diff: 3, q: "Which tree includes the oldest known living individual, nearly 4,900 years old?", options: ["Coast redwood", "Bristlecone pine", "Baobab", "English oak"], answer: 1, fact: "A bristlecone named 'Methuselah' sprouted around 2833 BCE — before the Great Pyramid of Giza was finished." },
  { cat: "Nature", diff: 3, q: "Where would you find the Challenger Deep, the ocean's deepest point?", options: ["Puerto Rico Trench", "Mariana Trench", "Java Trench", "Tonga Trench"], answer: 1, fact: "It lies about 10,935 m down — deeper than Everest is tall, under more than 1,000 times sea-level pressure." },
  { cat: "Nature", diff: 3, q: "Which is the largest living reptile?", options: ["Komodo dragon", "Green anaconda", "Saltwater crocodile", "Galapagos tortoise"], answer: 2, fact: "The saltwater crocodile has the strongest bite ever measured in a living animal — about 3,700 pounds of force." },
];
